import React from 'react';

export default function () {
  return (
    <header className="header">
      <a href="#" className="header__logo" title="ПРОДУКТУТ"></a>
      <div className="header__search">
        <i className="fa fa-search search-icon"></i>
        <input className="search-field" placeholder="Поиск продуктов" />
      </div>
      <div className="header__login">
        <a href="#" className="header__login-btn">Войти</a>
      </div>
    </header>
  );
}



