import React from 'react';

export default function () {
  return (
    <nav className="nav-header">
      <div className="location">
        <a href="#" className="location__item">
          Санкт-Петербург <i className="fa fa-angle-down location__item-down"></i>
        </a>
      </div>
      <div className="menu">
        <a href="#" className="menu__item">Магазины</a>
        <a href="#" className="menu__item">Категории
          <i className="fa fa-angle-down location__item-down"></i>
        </a>
        <a href="#" className="menu__item">Помощь</a>
      </div>
      <div className="cart">
        <a href="#" className="cart__item">
          Моя полка <span className="cart__item-circ">646464</span>
        </a>
      </div>
    </nav>
  );
}



