import React from 'react';
import classnames from 'classnames';

export default React.createClass({
  propTypes: {
    name: React.PropTypes.string.isRequired,
    title: React.PropTypes.string,
    opened: React.PropTypes.bool,
    openable: React.PropTypes.bool,
    children: React.PropTypes.object,
  },
  getDefaultProps() {
    return {
      title: '',
      opened: true,
      openable: true,
    };
  },
  getInitialState() {
    return {
      opened: this.props.opened,
    };
  },
  getName() {
    return this.props.name;
  },
  getValue() {
    const input = this.refs.input;
    if (input && input.getValue) {
      return input.getValue();
    }
    return '';
  },
  handleHeaderClick() {
    if (this.props.openable) {
      this.setState({
        opened: !this.state.opened,
      });
    }
  },
  render() {
    let children = this.props.children;
    if (children && !Array.isArray(children)) {
      children = React.cloneElement(children, { ref: 'input' });
    }
    const headerClasses = classnames(
      'facet__header',
      { facet__header_closed: !this.state.opened }
    );
    const bodyClasses = classnames(
      'facet__body',
      { facet__body_closed: !this.state.opened }
    );
    return (
      <div className="facet">
          <div onClick={this.handleHeaderClick} className={headerClasses}>
            <h4 className="facet__title">{this.props.title}</h4>
          </div>
          <div className={bodyClasses}>
            { children }
          </div>
        </div>
    );
  },
});



