import jquery from 'jquery';


export default {
  shopItem(where, sort) {
    console.log(where);
    return new Promise((resolve, reject) => {
      jquery.get('https://offerist.herokuapp.com/api/v0.0.1/json/shopitem', {
        populate: 'shop,product',
        where,
        sort,
      })
      .done(response => {
        resolve(response);
      })
      .fail(error => {
        reject(error);
      });
    });
  },
  loadFilters(schemaId) {
    console.log(schemaId);
    return new Promise((resolve, reject) => {
      jquery.get('https://offerist.herokuapp.com/schema')
      .done(response => {
        resolve(response);
      })
      .fail(error => {
        reject(error);
      });
    });
  },
};



