import React from 'react';
import history from '../../history';
// import { Router, Route, hashHistory } from 'react-router';

import HeaderContainer from '../HeaderContainer';
import NavHeader from '../NavHeader';
import ProductSearch from '../ProductSearch';
import ProductDetail from '../ProductDetail';

// <Router history={hashHistory}>
//   <Route path="/" component={ProductSearch} />
//   <Route path="/detail/:id" component={ProductDetail} />
// </Router>

const ROUTE_COMPONENTS = {
  ProductSearch,
  ProductDetail,
};


export default React.createClass({
  getInitialState() {
    return {
      routeComponent: 'ProductSearch',
    };
  },
  componentDidMount() {
    this.historyUnlisten = history.listen(this.handleHistoryChange);
  },
  componentWillUnmount() {
    this.historyUnlisten();
  },
  handleHistoryChange(location) {
    const found = location.pathname.match(/detail\/([0-9a-z]+)/);
    if (found && this.state.routeComponent !== 'ProductDetail') {
      this.setState({
        routeComponent: 'ProductDetail',
      });
    } else if (this.state.routeComponent !== 'ProductSearch') {
      this.setState({
        routeComponent: 'ProductSearch',
      });
    }
  },
  renderRoutComponent() {
    const RouteComponent = ROUTE_COMPONENTS[this.state.routeComponent];
    if (!RouteComponent) {
      return <div key="notFound">Страница не найдена</div>;
    }
    return <RouteComponent key={this.state.routeComponent} />;
  },
  render() {
    return (
      <div className="app">
        <HeaderContainer />
        <NavHeader />
        <main className="container">
          {this.renderRoutComponent() }
        </main>
      </div>
    );
  },
});



